sql:
SELECT downloads
FROM reports
WHERE report_id = 1;

SELECT name
FROM pollution_sources
WHERE operational_status = 'active';

SELECT school_id, health_risk_index
FROM school_pollution
ORDER BY health_risk_index DESC;

SELECT school_id, AVG(pollution_level) AS avg_pollution_level
FROM school_pollution
GROUP BY school_id;

external_knowledge:
- 'frequently active users' refers to users who have accessed data more than once within the last 30 days; 
- 'recently' refers to data access events that occurred within the last 30 days; 
- 'nearby sources' refers to pollution sources that have an active operational status.

sql:
SELECT name
FROM pollution_sources
WHERE pm25_tpy = (SELECT MAX(pm25_tpy) FROM pollution_sources);

SELECT last_inspection_date
FROM pollution_sources
WHERE source_id = 1;
